<template>
  <div class="page-container">
    <!-- е·Ұдҫ§з« иҠӮе®№еҷЁ -->
    <div class="chapter-list" ref="chapterList">
      <div class="panel-header">
        <div class="panel-title">з« иҠӮзӣ®еҪ•</div>
        <div class="panel-subtitle">йҖүжӢ©зҜҮзӣ®жҹҘзңӢи·ҜзәҝдёҺж—¶й—ҙиҪҙ</div>
      </div>
      <div
        v-for="(chapter, index) in chapters"
        :key="index"
        class="chapter-item"
        :class="{ active: activeChapter === index }"
        :data-index="index"
        @click="selectChapter(index)"
      >
        {{ chapter }}
      </div>
    </div>
    <!-- дёӯй—ҙз« иҠӮе®№еҷЁ -->
    <div class="page-content">
      <!-- зҹўйҮҸе®№еҷЁ -->
      <div ref="mapContainer" class="map-container">
        <img src="/images/south.png" alt="еҚ—жө·" class="south-china-sea-image" />
      </div>
    </div>
    <!-- еҸідҫ§ж•…дәӢе®№еҷЁ -->   
    <div class="story-content">
      <div id="place-impo-container" class="top-content">
        <!-- дёҠйқўзҡ„еҶ…е®№ -->
        <div class="card-header">
          <h3 class="title">ең°зӮ№дҝЎжҒҜ</h3>
          <div class="hint">зӮ№еҮ»ж—¶й—ҙиҪҙдёӢж–№зҡ„еҚЎзүҮжҹҘзңӢ</div>
        </div>
        <p class="inner-content" v-html="placeInfoDisplay"></p>
      </div>
      <div id="place-info-container" class="bottom-content">
        <!-- дёӢйқўзҡ„еҶ…е®№ -->
        <div class="card-header">
          <h3 class="title">йҮҚиҰҒдәӢд»¶</h3>
          <div class="hint">ж”ҜжҢҒж»ҡеҠЁжҹҘзңӢе®Ңж•ҙеҶ…е®№</div>
        </div>
        <p class="inner-content" v-html="placeImpoDisplay"></p>
      </div>
    </div>
  </div>
</template>

<script>
import * as d3 from "d3";

export default {
  name: "PageOne",
  data() {
    return {
      timelineY: 0,
      timelineX: 0,
      len: 4,
      init:0,

      svg: null,        // SVG еҜ№иұЎ
      projection: null, // еӯҳеӮЁең°еӣҫжҠ•еҪұеҜ№иұЎ

      chapters: [], // еӯҳеӮЁз« иҠӮеҗҚ
      activeChapter: null, // еҪ“еүҚйҖүдёӯзҡ„з« иҠӮзҙўеј•

      locations: [], // еӯҳеӮЁең°зӮ№дҝЎжҒҜ
      selectedLocations: [], // еӯҳеӮЁйҖүдёӯзҡ„ең°зӮ№ж•°жҚ®

      timeData: [], // еӯҳеӮЁжңүж—¶й—ҙдҝЎжҒҜзҡ„ж•°жҚ®
      selectedTimeData: [], // еӯҳеӮЁйҖүдёӯзҡ„ж—¶й—ҙж•°жҚ®

      lines: [],  // еҠЁжҖҒеӯҳеӮЁжӣІзәҝж•°жҚ®

      placeInfoDisplay: "иҝҷйҮҢдјҡжҳҫзӨәең°зӮ№дҝЎжҒҜ", // й»ҳи®ӨдҝЎжҒҜ
      placeImpoDisplay: "иҝҷйҮҢдјҡжҳҫзӨәйҮҚиҰҒдәӢд»¶дҝЎжҒҜ", // й»ҳи®ӨдҝЎжҒҜ.", // й»ҳи®ӨйҮҚиҰҒдәӢд»¶дҝЎжҒҜ

      theme: {
        ink: "#1f2424",
        paperStroke: "rgba(31, 36, 36, 0.12)",
        landFill: "#dcd1b2",
        landHover: "#cbbf9b",
        routeBase: "rgba(31, 36, 36, 0.35)",
        routeActive: "#b33a2b",
        pointBase: "rgba(31, 36, 36, 0.55)",
        pointActive: "#b33a2b",
        timeAxis: "rgba(31, 36, 36, 0.22)",
        timeDot: "rgba(179, 58, 43, 0.55)",
        timeLink: "rgba(31, 36, 36, 0.22)",
      },
    };
  },
  async mounted() {
    // йҰ–ж¬ЎеҠ иҪҪж—¶
    await this.initOnResize();
    // зӣ‘еҗ¬зӘ—еҸЈеӨ§е°ҸеҸҳеҢ–
    window.addEventListener('resize', this.initOnResize);
  },
  beforeUnmount() {
    // з§»йҷӨзӣ‘еҗ¬пјҢйҒҝе…ҚеҶ…еӯҳжі„жјҸ
    window.removeEventListener('resize', this.initOnResize);
  },
  methods: {
    // зЁіе®ҡдјӘйҡҸжңәпјҲз”ЁдәҺжһҒе°Ҹжү°еҠЁпјҢйҒҝе…Қе®Ңе…ЁеҜ№йҪҗпјү
    seeded01(key) {
      const s = String(key);
      let h = 2166136261;
      for (let i = 0; i < s.length; i++) {
        h ^= s.charCodeAt(i);
        h = Math.imul(h, 16777619);
      }
      h ^= h << 13; h ^= h >>> 17; h ^= h << 5;
      return ((h >>> 0) % 10000) / 10000;
    },

    getChapterIndexByName(chapterName) {
      if (!chapterName || !Array.isArray(this.chapters) || this.chapters.length === 0) return -1;
      return this.chapters.findIndex((c) => c === chapterName);
    },

    activateChapterByName(chapterName) {
      const idx = this.getChapterIndexByName(chapterName);
      if (idx >= 0) this.selectChapter(idx);
    },

    async initOnResize() {
      this.resetData();
      // зӯүеҫ…ејӮжӯҘж•°жҚ®еҠ иҪҪ
      await Promise.all([
        this.loadChapters(),  // ејӮжӯҘеҠ иҪҪз« иҠӮж•°жҚ®
        this.loadLocationData(),  // ејӮжӯҘеҠ иҪҪең°зӮ№ж•°жҚ®
        this.loadTimeData(),  // ејӮжӯҘеҠ иҪҪж—¶й—ҙж•°жҚ®
      ]);
      this.initMap();  // еҲқе§ӢеҢ–ең°еӣҫ
    },
    resetData() {
      this.timelineY = 0;
      this.timelineX = 0;
      this.init = 0;
      const container = this.$refs.mapContainer; // иҺ·еҸ–ең°еӣҫе®№еҷЁ
      // // жё…з©әжүҖжңүеӣҫеғҸ
      // const images = container.querySelectorAll('img');
      // images.forEach(img => img.remove());  // з§»йҷӨжүҖжңүеӣҫеғҸ

      // жё…з©әжүҖжңү SVG е…ғзҙ 
      const svgs = container.querySelectorAll('svg');
      svgs.forEach(svg => svg.remove());  // з§»йҷӨжүҖжңү SVG е…ғзҙ 
      this.svg = null;        // SVG еҜ№иұЎ
      this.projection = null; // ең°еӣҫжҠ•еҪұеҜ№иұЎ
    },
       // еҠ иҪҪз« иҠӮеҗҚ
    async loadChapters() {
      try {
        const response = await fetch("/data/chapters.json"); // JSON ж–Үд»¶и·Ҝеҫ„
        const data = await response.json();
        this.chapters = data.chapters;
      } catch (error) {
        console.error("Failed to load chapters:", error);
      }
    },
    // жҸҗеҸ–ж—¶й—ҙдёӯзҡ„з¬¬дёҖдёӘе№ҙд»Ҫ
    extractDate(timeString) {
      if (timeString == null) {
        return new Date(1940, 0, 1); // еҰӮжһңжІЎжңүж—¶й—ҙпјҢй»ҳи®Өдёә 1940 е№ҙ 1 жңҲ 1 ж—Ҙ
      }

      // 1. жҸҗеҸ–е№ҙд»ҪпјҲжӢ¬еҸ·дёӯзҡ„еӣӣдҪҚж•°еӯ—пјү
      const yearRegex = /[пјҲ(](\d{4})[пјү)]/;
      const yearMatch = timeString.match(yearRegex); // иҺ·еҸ–е№ҙд»ҪеҢ№й…Қз»“жһң
      const year = yearMatch ? parseInt(yearMatch[1], 10) : 1940;  // еҰӮжһңжүҫеҲ°е№ҙд»ҪпјҢиҝ”еӣһе№ҙд»ҪпјҢеҗҰеҲҷй»ҳи®Өдёә 1940 е№ҙ

      // 2. жҸҗеҸ–жңҲд»ҪпјҲеҰӮжһңжңүжңҲеӯ—пјү
      const monthRegex = /(\d+)(?=жңҲ)/;  // еҢ№й…Қж•°еӯ—е’ҢеҗҺйқўзҡ„"жңҲ"
      const monthMatch = timeString.match(monthRegex);
      const month = monthMatch ? parseInt(monthMatch[1], 10) - 1 : 0;  // жңҲд»Ҫд»Һ0ејҖе§ӢпјҢжІЎжүҫеҲ°еҲҷй»ҳи®Өдёә1жңҲ

      // 3. жҸҗеҸ–ж—ҘжңҹпјҲеҰӮжһңжңүж—Ҙеӯ—пјү
      const dayRegex = /(\d+)(?=ж—Ҙ)/;  // еҢ№й…Қж•°еӯ—е’ҢеҗҺйқўзҡ„"ж—Ҙ"
      const dayMatch = timeString.match(dayRegex);
      const day = dayMatch ? parseInt(dayMatch[1], 10) : 1;  // жІЎжүҫеҲ°еҲҷй»ҳи®Өдёә1ж—Ҙ

      // иҝ”еӣһжһ„йҖ зҡ„ж—ҘжңҹеҜ№иұЎ
      return new Date(year, month, day);  // иҝ”еӣһж №жҚ®жҸҗеҸ–зҡ„е№ҙд»ҪгҖҒжңҲд»ҪгҖҒж—Ҙжңҹз”ҹжҲҗзҡ„ж—ҘжңҹеҜ№иұЎ
    },

    // еҠ иҪҪең°зӮ№ж•°жҚ®
    async loadLocationData() {
      try {
        const response = await fetch("/data/dataset_total.json"); // ж•°жҚ®ж–Үд»¶и·Ҝеҫ„
        const data = await response.json();
        // еҸӘжҸҗеҸ–ең°еҗҚе’Ңз»Ҹзә¬еәҰ
        this.locations = data.map(item => ({
          name: item["ең°еҗҚ"],
          lon: item["ең°зӮ№з»ҸеәҰпјҲй»ҳи®Өдёңз»Ҹпјү"],
          lat: item["ең°зӮ№зә¬еәҰпјҲй»ҳи®ӨеҢ—зә¬пјү"],
          chapter: item["жүҖеұһзҜҮзӣ®"],  // ж·»еҠ вҖңжүҖеұһзҜҮзӣ®вҖқеӯ—ж®ө
          route: item["иҜҰз»Ҷи·Ҝзәҝ"],    // ж·»еҠ вҖңиҜҰз»Ҷи·ҜзәҝвҖқеӯ—ж®ө
          // time: this.extractYear(item["жёёеҺҶж—¶й—ҙ"])  // жҸҗеҸ–е№ҙд»Ҫ
        }));
        
      } catch (error) {
        console.error("Failed to load location data:", error);
      }
    },
    // еҠ иҪҪж—¶й—ҙж•°жҚ®
    async loadTimeData() {
      try {
        const response = await fetch("/data/dataset_time.json"); // ж•°жҚ®ж–Үд»¶и·Ҝеҫ„
        const data = await response.json();
        // еҸӘжҸҗеҸ–ең°еҗҚе’Ңз»Ҹзә¬еәҰ
        this.timeData = data.map(item => ({
          name: item["ең°еҗҚ"],
          lon: item["ең°зӮ№з»ҸеәҰпјҲй»ҳи®Өдёңз»Ҹпјү"],
          lat: item["ең°зӮ№зә¬еәҰпјҲй»ҳи®ӨеҢ—зә¬пјү"],
          chapter: item["жүҖеұһзҜҮзӣ®"],  // ж·»еҠ вҖңжүҖеұһзҜҮзӣ®вҖқеӯ—ж®ө
          route: item["иҜҰз»Ҷи·Ҝзәҝ"],    // ж·»еҠ вҖңиҜҰз»Ҷи·ҜзәҝвҖқеӯ—ж®ө
          time: this.extractDate(item["жёёеҺҶж—¶й—ҙ"]),  // жҸҗеҸ–е№ҙд»Ҫ
          info: item["ең°зӮ№дҝЎжҒҜиЎҘе……пјҲжқҘиҮӘзҷҫз§‘пјү"],
          impo: item["йҮҚиҰҒдәӢд»¶"],
        }));
        console.log("Original data length:", data.length);
        console.log("Processed timeData length:", this.timeData.length);

      } catch (error) {
        console.error("Failed to load location data:", error);
      }
    },

    // йҖүжӢ©з« иҠӮ
    selectChapter(index) {
      this.activeChapter = index;
      const selectedChapter = this.chapters[index];
      console.log("1");
      // зӯӣйҖүеҮә"жүҖеұһзҜҮзӣ®"дёәйҖүдёӯз« иҠӮзҡ„ж•°жҚ®
      this.selectedLocations = this.locations.filter(item => item.chapter === selectedChapter);
      // зӯӣйҖүеҮә"жүҖеұһзҜҮзӣ®"дёәйҖүдёӯз« иҠӮзҡ„ж•°жҚ®
      this.selectedTimeData = this.timeData.filter(item => item.chapter === selectedChapter);
      this.init = 1;
      // е…іиҒ”ең°зӮ№е’Ңж—¶й—ҙж•°жҚ®
      this.relate();

      // иҮӘеҠЁж»ҡеҠЁз« иҠӮзӣ®еҪ•еҲ°еҪ“еүҚйЎ№
      this.$nextTick(() => {
        const container = this.$refs.chapterList;
        if (!container || !container.querySelector) return;
        const el = container.querySelector(`[data-index="${index}"]`);
        if (el && typeof el.scrollIntoView === "function") {
          el.scrollIntoView({ block: "nearest", behavior: "smooth" });
        }
      });
    },
    // з»ҳеҲ¶ең°еӣҫи·Ҝеҫ„
    async drawMapPath(svg, projection) {
      return new Promise((resolve, reject) => {
        d3.json("/data/china.geo.json").then(mapData => {
          const path = d3.geoPath().projection(projection);
          svg.append("g")
            .selectAll("path")
            .data(mapData.features)
            .enter()
            .append("path")
            .attr("d", path)
            .style("fill", this.theme.landFill)
            .style("stroke", this.theme.paperStroke)
            .style("stroke-width", 0.6)
            .on("mouseover", (event, d) => {
              d3.select(event.currentTarget).style("fill", this.theme.landHover);
              this.createTooltip(svg, d, event);
            })
            // .on("mousemove", (event) => {
            //   this.removeTooltip();
            //   this.createTooltip(svg, null, event);
            // })
            .on("mouseout", (event) => {
              d3.select(event.currentTarget).style("fill", this.theme.landFill);
              this.removeTooltip();
            });

          // з»ҳеҲ¶е®ҢжҲҗеҗҺи°ғз”Ё resolve
          resolve();
        }).catch(reject); // еҰӮжһңеӨұиҙҘпјҢеҲҷи°ғз”Ё reject
      });
    },
    // еңЁйҖүжӢ©з« иҠӮж—¶е…іиҒ”ең°еӣҫдёҠзҡ„зӮ№е’Ңж—¶й—ҙж Үе°ә
    async relate() {
      // const container = this.$refs.mapContainer;
      // const width = container.clientWidth;
      // const height = container.clientHeight;
      // const centerX = width / 2;
      

      const svg = d3.select(this.$refs.mapContainer).select("svg");  // йҖүжӢ©ең°еӣҫзҡ„ svg е®№еҷЁ
      svg.selectAll("circle").remove();  // жё…йҷӨд№ӢеүҚз»ҳеҲ¶зҡ„ең°зӮ№еңҶеңҲ
      svg.selectAll(".location-line").remove();
      svg.selectAll(".tick").remove();
      // й«ҳдә®еҪ“еүҚз« иҠӮзҡ„ең°зӮ№пјҢзҒ°иүІе…¶д»–ең°зӮ№
      await this.drawLocationCircles(svg, this.projection, this.selectedLocations);
      await this.drawLocationLines(svg, this.projection, this.selectedLocations, this.len);
      
      // иҺ·еҸ–ж—¶й—ҙж Үе°әе®№еҷЁзҡ„ g е…ғзҙ 
      const timelineGroup = svg.select(".timeline-group");
    
      // const timelineWidth = svg.node().getBoundingClientRect().width;
      const timelineWidth = this.timelineX;
      const timelineHeight = 60;  // ж—¶й—ҙж Үе°әзҡ„й«ҳеәҰ

      const centerY = this.timelineY;

      // 1. жё…йҷӨд№ӢеүҚзҡ„ж—¶й—ҙиҝһжҺҘзәҝе’Ңж—¶й—ҙзӮ№
      svg.selectAll(".timeline-link").remove();
      svg.selectAll(".location-circle").remove();  // жё…йҷӨд№ӢеүҚз»ҳеҲ¶зҡ„ең°зӮ№еңҶеңҲ
      timelineGroup.selectAll(".timeline-point").remove(); // axis-labelжё…йҷӨд№ӢеүҚзҡ„ж—¶й—ҙзӮ№
      svg.selectAll(".axis-label").remove();
      timelineGroup.selectAll(".timeline-text").remove();
      // жё…йҷӨд№ӢеүҚз»ҳеҲ¶зҡ„ж—¶й—ҙиҪҙ
      timelineGroup.select(".timeline-axis").remove();

      // ж—¶й—ҙж•°жҚ®иҢғеӣҙ
      const minDate = d3.min(this.selectedTimeData, d => new Date(d.time));
      const maxDate = d3.max(this.selectedTimeData, d => new Date(d.time));

      // и®Ўз®—ж—¶й—ҙи·ЁеәҰпјҲд»ҘжҜ«з§’дёәеҚ•дҪҚпјү
      const timeSpan = maxDate - minDate;

      // ж №жҚ®ж—¶й—ҙи·ЁеәҰеҠЁжҖҒи°ғж•ҙжңҖе°Ҹе’ҢжңҖеӨ§ж—Ҙжңҹ
      let adjustedMinDate, adjustedMaxDate;
      if (timeSpan <= 365 * 24 * 60 * 60 * 1000) {  // е°ҸдәҺдёҖе№ҙ
        adjustedMinDate = d3.timeMonth.offset(minDate, -1);  // жңҖе°Ҹж—Ҙжңҹдёәе®һйҷ…жңҖе°Ҹж—Ҙжңҹзҡ„еүҚ1дёӘжңҲ
        adjustedMaxDate = d3.timeMonth.offset(maxDate, 1);   // жңҖеӨ§ж—Ҙжңҹдёәе®һйҷ…жңҖеӨ§ж—Ҙжңҹзҡ„еҗҺ1дёӘжңҲ
      } else {  // еӨ§дәҺдёҖе№ҙ
        adjustedMinDate = d3.timeYear.offset(minDate, -1);   // жңҖе°Ҹж—Ҙжңҹдёәе®һйҷ…жңҖе°Ҹж—Ҙжңҹзҡ„еүҚ1е№ҙ
        adjustedMaxDate = d3.timeYear.offset(maxDate, 1);    // жңҖеӨ§ж—Ҙжңҹдёәе®һйҷ…жңҖеӨ§ж—Ҙжңҹзҡ„еҗҺ1е№ҙ
      }

      // 2. ж №жҚ®йҖүдёӯзҡ„ж—¶й—ҙж•°жҚ®пјҢжӣҙж–°ж—¶й—ҙж Үе°ә
      const xScale = d3.scaleTime()
        .domain([adjustedMinDate, adjustedMaxDate])
        .range([30, timelineWidth - 30]);

      // еҠЁжҖҒи®ҫзҪ®ж—¶й—ҙеҲ»еәҰзҡ„й—ҙйҡ”
      const interval = timeSpan <= 365 * 24 * 60 * 60 * 1000 // е°ҸдәҺдёҖе№ҙ
        ? d3.timeMonth.every(1)  // жҜҸжңҲдёҖдёӘеҲ»еәҰ
        : d3.timeYear.every(1);  // жҜҸе№ҙдёҖдёӘеҲ»еәҰ

      // з»ҳеҲ¶ж—¶й—ҙиҪҙеҲ»еәҰ
      const axisBottom = d3.axisBottom(xScale)
        .ticks(interval)
        .tickFormat(d3.timeFormat("%Y-%m"))
        .tickSizeInner(8)
        .tickSizeOuter(0);
      timelineGroup.append("g")
        .attr("class", "timeline-axis")
        .attr("transform", `translate(0, ${centerY + timelineHeight / 2})`)
        .call(axisBottom)
        .selectAll(".tick text") // йҖүжӢ©еҲ»еәҰж–Үжң¬
        .style("font-size", "15px") // и°ғеӨ§еӯ—дҪ“
        .style("font-weight", "bold") // еҠ зІ—еӯ—дҪ“
        .style("fill", "#000000"); //иҝҷйҮҢжҳҜи°ғж—¶й—ҙеҲ»еәҰж–Үжң¬зҡ„йўңиүІ

      // дҝ®ж”№еҲ»еәҰзәҝзҡ„ж ·ејҸ
      timelineGroup.selectAll(".tick line") // дҝ®ж”№еҲ»еәҰзәҝзҡ„йўңиүІ
        .attr("y1", 0)
        .attr("y2", 8)
        .style("stroke", this.theme.timeAxis)
        .style("stroke-width", "1");

      // йҡҗи—ҸжЁӘиҪҙзәҝ (еҚі path е…ғзҙ )
      timelineGroup.select(".timeline-axis path")
          .style("display", "none"); // йҡҗи—ҸжЁӘиҪҙзәҝ

      // з»ҳеҲ¶ж—¶й—ҙиҪҙдёҠзҡ„жҜҸдёӘзӮ№
      timelineGroup.selectAll(".timeline-point")
        .data(this.selectedTimeData)
        .enter()
        .append("circle")
        .attr("class", "timeline-point")
        .attr("cx", (d, i) => {
          const baseX = xScale(new Date(d.time)); // ж №жҚ®ж—¶й—ҙз»ҳеҲ¶дҪҚзҪ®
          const offsetX = i * 0;  // ж №жҚ®зҙўеј•дёәзӮ№ж·»еҠ ж°ҙе№іеҒҸз§»пјҲдҪ еҸҜд»Ҙи°ғж•ҙиҝҷдёӘеҖјпјү
          return baseX + offsetX; // ж·»еҠ еҒҸз§»еҗҺзҡ„Xеқҗж Ү
        })
        .attr("cy", centerY + timelineHeight / 2) // еңЁж—¶й—ҙж Үе°әдёӯеұ…дёӯжҳҫзӨә
        .attr("r", 5.5)
        .attr("fill", this.theme.timeDot)
        .style("opacity", 0.85);
        
      const mini = 40; // и®ҫзҪ®жңҖе°Ҹи·қзҰ»
      // 2. з»ҳеҲ¶ж—¶й—ҙж–Үжң¬
      timelineGroup.selectAll(".timeline-text")
        .data(this.selectedTimeData)
        .enter()
        .append("text")
        .attr("class", "timeline-text")
        .attr("x", (d, i) => {
          const baseX = xScale(new Date(d.time)); // ж №жҚ®ж—¶й—ҙз»ҳеҲ¶дҪҚзҪ®
          const offsetX = i * 0;  // ж №жҚ®зҙўеј•дёәзӮ№ж·»еҠ ж°ҙе№іеҒҸз§»
          return baseX + offsetX;
        })
        .attr("y", centerY + 20 + timelineHeight / 2) // ж–Үеӯ—дҪҚзҪ®зЁҚеҫ®еңЁзӮ№зҡ„дёӢж–№
        .attr("dy", -30) // еҫ®и°ғж–Үеӯ—зҡ„еһӮзӣҙдҪҚзҪ®
        .attr("text-anchor", "middle") // ж–Үеӯ—еұ…дёӯжҳҫзӨә
        .text((d, i, nodes) => {
          const currentX = xScale(new Date(d.time)); // еҪ“еүҚзӮ№зҡ„xеқҗж Ү
          const leftX = i > 0 ? xScale(new Date(this.selectedTimeData[i - 1].time)) : -Infinity;
          const rightX = i < this.selectedTimeData.length - 1 ? xScale(new Date(this.selectedTimeData[i + 1].time)) : Infinity;
          // иҝ”еӣһеҸӘеҢ…еҗ«вҖңж—ҘжңҲвҖқзҡ„ж јејҸ
          const date = new Date(d.time);
          const options = { month: '2-digit', day: '2-digit' }; // ж јејҸдёә MM/DD

          if(i===0 || i===this.selectedTimeData.length-1){
              return new Intl.DateTimeFormat('en-US', options).format(date); // жҲ– 'en-US' зӯү
            }
          // еҰӮжһңдёҺе·ҰеҸізӮ№зҡ„и·қзҰ»йғҪе°ҸдәҺ miniпјҢдёҚжҳҫзӨәж–Үеӯ—:&& Math.abs(currentX - rightX) < mini
          if (Math.abs(currentX - leftX) < mini) {
            nodes[i].remove(); // з§»йҷӨиҜҘе…ғзҙ 
            return null; // дёҚи®ҫзҪ®ж–Үжң¬
          }
          if(i===this.selectedTimeData.length-2 && Math.abs(currentX - rightX) < mini){
            nodes[i].remove(); // з§»йҷӨиҜҘе…ғзҙ 
            return null; // дёҚи®ҫзҪ®ж–Үжң¬
          }
          return new Intl.DateTimeFormat('en-US', options).format(date); // жҲ– 'en-US' зӯү
        })
        .style("font-size", "15px")
        .style("font-weight", "bold") // еҠ зІ—еӯ—дҪ“
        .style("fill", "#000000");// иҝҷйҮҢжҳҜи°ғж—¶й—ҙиҪҙдёҠжёёи®ҝең°еӣҫең°зӮ№зҡ„ж—¶й—ҙж–Үжң¬зҡ„йўңиүІ

      // 3. ж·»еҠ еқҗж ҮиҪҙеҗҚз§°пјҲж—¶й—ҙиҪҙеҗҚз§°пјү
      svg.append("text")
        .attr("class", "axis-label")
        .attr("x", (timelineWidth *0.95))  // е°Ҷж–Үжң¬ж”ҫзҪ®еңЁз”»еёғзҡ„дёӯеҝғ
        .attr("y", centerY + timelineHeight / 2 - 10) // ж”ҫзҪ®еңЁж—¶й—ҙиҪҙдёӢж–№
        .attr("text-anchor", "middle")
        .text("ж—¶й—ҙиҪҙ")  // и®ҫзҪ®еқҗж ҮиҪҙзҡ„еҗҚз§°
        .style("font-size", "16px")
        .style("font-weight", "bold");// иҝҷйҮҢеҸҜд»Ҙи°ғ"ж—¶й—ҙиҪҙ"ж–Үжң¬зҡ„йўңиүІгҖҒеӨ§е°Ҹзӯү

      // 4. з»ҳеҲ¶ж—¶й—ҙиҝһжҺҘзәҝпјҲд»ҺжҜҸдёӘең°зӮ№еҲ°ж—¶й—ҙзӮ№пјү
      const lineGroup = svg.append("g").attr("class", "timeline-link");


      // еҲӣе»әдёҖдёӘж—¶й—ҙиҪҙдёҠзҡ„зӮ№дёҺең°еӣҫдёҠең°зӮ№д№Ӣй—ҙзҡ„иҝһжҺҘжӣІзәҝ
      lineGroup.selectAll("path")  // дҪҝз”ЁpathиҖҢдёҚжҳҜlineжқҘз»ҳеҲ¶жӣІзәҝ
          .data(this.selectedTimeData)
          .enter()
          .append("path")
          .attr("class", "timeline-link")
          .attr("d", (d, i) => {
            // дёәз»ҲзӮ№ж·»еҠ еҒҸз§»йҮҸпјҢйҒҝе…ҚйҮҚеҸ 
            const offsetX = i * 0;  // еҸҜд»Ҙж №жҚ®зҙўеј•и°ғж•ҙеҒҸз§»йҮҸпјҲдҫӢеҰӮ 5pxпјү
            const offsetY = 0;  // еҸҜд»Ҙж №жҚ®йңҖиҰҒеңЁyж–№еҗ‘дёҠеҠ еҒҸз§»пјҢи°ғж•ҙз»ҲзӮ№зҡ„yдҪҚзҪ®

            // е®ҡд№үжӣІзәҝзҡ„иө·зӮ№е’Ңз»ҲзӮ№д»ҘеҸҠжҺ§еҲ¶зӮ№
            const start = [xScale(new Date(d.time)) + offsetX, centerY + timelineHeight / 2 + offsetY];  // ж—¶й—ҙзӮ№зҡ„xеқҗж Үе’Ңyеқҗж Ү
            

            // ең°зӮ№зҡ„xеқҗж Үе’Ңyеқҗж ҮпјҢж·»еҠ еҒҸз§»йҮҸ
            const end = this.projection([d.lon, d.lat]);
            

            // е®ҡд№үжҺ§еҲ¶зӮ№з”ЁдәҺз»ҳеҲ¶жӣІзәҝ (дҪ еҸҜд»Ҙж №жҚ®йңҖиҰҒи°ғж•ҙжҺ§еҲ¶зӮ№зҡ„дҪҚзҪ®)
            const controlPoint = [
                (start[0] + end[0]) / 2, // жҺ§еҲ¶зӮ№зҡ„xеқҗж Ү
                (start[1] + end[1]) / 2 - 50  // жҺ§еҲ¶зӮ№зҡ„yеқҗж ҮпјҢеҒҸз§»дҪҝжӣІзәҝжңүејҜжӣІ
            ];

              // дҪҝз”ЁиҙқеЎһе°”жӣІзәҝиҝӣиЎҢз»ҳеҲ¶
            return d3.line().curve(d3.curveCardinal).x(d => d[0]).y(d => d[1])([start, controlPoint, end]);
              // жӣІзәҝзҡ„иө·зӮ№гҖҒжҺ§еҲ¶зӮ№е’Ңз»ҲзӮ№
          })
          .attr("fill", "none")
          .attr("stroke", "#f19c4c")// ж—¶й—ҙиҪҙдёҠзҡ„зӮ№дёҺең°еӣҫдёҠең°зӮ№д№Ӣй—ҙзҡ„иҝһжҺҘжӣІзәҝ(v1:b7ae8f)
          .attr("stroke-width", 2)
          .style("opacity", 0.5)
          .style("stroke-dasharray", "4,4");  // ж·»еҠ иҷҡзәҝж•Ҳжһң
      // з»ҳеҲ¶жҜҸдёӘж—¶й—ҙзӮ№дёӢж–№зҡ„еңҶи§’зҹ©еҪў
      // дёӨеұӮж ҮзӯҫйҒҝзў°пјҡдҝқжҢҒе·ҰеҸійЎәеәҸдёҚеҸҳпјҢе…Ғи®ёйҖӮеәҰж°ҙе№іеӣһжҺЁ
      const rectWidth = 42;
      const rectHeight = 92;
      const baseY = centerY + 72; // ж•ҙдҪ“жӣҙйқ иҝ‘ж—¶й—ҙиҪҙ
      const laneStep = 108;
      const laneCount = 2;
      const minGap = rectWidth + 18;
      const padX = 36;
      const xMin = padX + rectWidth / 2;
      const xMax = (timelineWidth - padX) - rectWidth / 2;

      const lastRight = new Array(laneCount).fill(-Infinity);
      const layout = this.selectedTimeData.map((d, i) => {
        const baseX = xScale(new Date(d.time));
        const key = `${d.name}-${d.time}-${i}`;
        const tryLane = (lane) => {
          const minCenter = lastRight[lane] === -Infinity
            ? xMin
            : (lastRight[lane] + minGap + rectWidth / 2);
          const x = Math.min(xMax, Math.max(baseX, minCenter));
          const shift = Math.abs(x - baseX);
          return { lane, x, shift };
        };
        const a = tryLane(0);
        const b = tryLane(1);
        const picked = a.shift <= b.shift ? a : b;
        lastRight[picked.lane] = picked.x + rectWidth / 2;
        // жһҒе°Ҹжү°еҠЁйҒҝе…Қе®Ңе…ЁеҜ№йҪҗ
        const jitter = (this.seeded01(`${key}-jx`) * 2 - 1) * 3;
        const xJ = Math.min(xMax, Math.max(xMin, picked.x + jitter));
        return { x: xJ, y: baseY + picked.lane * laneStep, lane: picked.lane, baseX };
      });

      const maxLeftDrift = 140;
      for (let lane = 0; lane < laneCount; lane++) {
        const idxs = layout
          .map((it, idx) => ({ it, idx }))
          .filter(x => x.it.lane === lane)
          .map(x => x.idx);
        for (let t = idxs.length - 2; t >= 0; t--) {
          const i0 = idxs[t];
          const i1 = idxs[t + 1];
          const targetMax = layout[i1].x - minGap;
          const driftMin = Math.max(xMin, layout[i0].baseX - maxLeftDrift);
          layout[i0].x = Math.max(driftMin, Math.min(layout[i0].x, targetMax));
        }
        for (let t = 1; t < idxs.length; t++) {
          const prev = layout[idxs[t - 1]];
          const cur = layout[idxs[t]];
          const minAllowed = prev.x + minGap;
          cur.x = Math.min(xMax, Math.max(cur.x, minAllowed));
        }
      }
      lineGroup.selectAll(".timeline-rect")
        .data(this.selectedTimeData)
        .enter()
        .append("rect")
        .attr("class", "timeline-rect")
        .attr("x", (d, i) => {
          return layout[i].x - rectWidth / 2;
        })
        .attr("y", (d, i) => {
          return layout[i].y;
        })
        .attr("width", rectWidth)
        .attr("height", rectHeight)
        .attr("rx", 0)
        .attr("ry", 0)
        .attr("fill", "rgba(255,255,255,0.18)")
        .attr("stroke", "rgba(31,36,36,0.22)")
        .attr("stroke-width", 1)
        .attr("style", "pointer-events: visible")
        .on("click", (event, d) => {  // дҪҝз”Ёз®ӯеӨҙеҮҪж•°
          console.log(this);  // зЎ®дҝқ this жҢҮеҗ‘дәҶ rect е…ғзҙ 
          const placeImpo = d.impo;
          const placeInfo = d.info;
          this.placeImpoDisplay = placeImpo ? placeImpo : "ж— ";
          this.placeInfoDisplay = placeInfo ? placeInfo : "ж— ";
            // и®ҫзҪ®зӮ№еҮ»еҗҺйўңиүІдёәзҷҪиүІ
          // d3.select(event.target).attr("fill", "#f9f9f9");
        })
        .on("mouseover", function() {
          d3.select(this)  // йҖүжӢ©еҪ“еүҚзҡ„зҹ©еҪў
            .transition()  // ж·»еҠ иҝҮжёЎж•Ҳжһң
            .duration(300)  // и®ҫзҪ®иҝҮжёЎж—¶й—ҙдёә300ms
            .attr("fill", "#f9f9f9")  // йј ж Үз»ҸиҝҮж—¶ж”№еҸҳеңҶи§’зҹ©еҪўйўңиүІ
            .attr("cursor", "pointer")  // ж”№еҸҳйј ж Үе…үж ҮдёәжүӢеҪў
            .style("opacity", 0.8);  // ж”№еҸҳйҖҸжҳҺеәҰ
        })
        .on("mouseout", function() {
          d3.select(this)  // йҖүжӢ©еҪ“еүҚзҡ„зҹ©еҪў
            .transition()  // ж·»еҠ иҝҮжёЎж•Ҳжһң
            .duration(300)  // и®ҫзҪ®иҝҮжёЎж—¶й—ҙдёә300ms
            .attr("fill", "rgba(255,255,255,0.18)")
            .style("opacity", 1);  // жҒўеӨҚйҖҸжҳҺеәҰ
        });


      // з»ҳеҲ¶жҜҸдёӘзҹ©еҪўе’Ңж—¶й—ҙзӮ№д№Ӣй—ҙзҡ„иҝһжҺҘжҠҳзәҝпјҲжңҖеӨҡжҠҳдёӨж¬Ўпјү
      lineGroup.selectAll(".timeline-line")
        .data(this.selectedTimeData)
        .enter()
        .append("path")
        .attr("class", "timeline-line")
        .attr("d", (d, i) => {
          const x1 = xScale(new Date(d.time));
          const y1 = centerY + timelineHeight / 2;
          const x2 = layout[i].x;
          const y2 = layout[i].y + 10;
          const yMidBase = centerY + 70;
          const yMid = yMidBase + (layout[i].lane === 0 ? 0 : 16);
          return `M ${x1} ${y1} L ${x1} ${yMid} L ${x2} ${yMid} L ${x2} ${y2}`;
        })
        .attr("fill", "none")
        .attr("stroke", this.theme.timeLink)
        .attr("stroke-width", 1.2)
        .style("opacity", 0.9);
      // const rectWidth = 30;  // и®ҫзҪ®зҹ©еҪўе®ҪеәҰ
      // const rectHeight = 80; // и®ҫзҪ®зҹ©еҪўй«ҳеәҰ
      // еңЁзҹ©еҪўдёӯж·»еҠ ж–Үжң¬
      lineGroup.selectAll(".timeline-text")
        .data(this.selectedTimeData)
        .enter()
        .append("text")
        .attr("class", "timeline-text")
        .attr("x", (d, i) => {
          return layout[i].x;
        })
        .attr("y", (d, i) => {
          return layout[i].y;
        })
        .attr("text-anchor", "middle")
        .attr("font-size", "12px")
        .attr("font-weight", "900")
        .attr("fill", "#000")//зҹ©еҪўдёӯж·»еҠ ж–Үжң¬зҡ„йўңиүІ
        .attr("style", "pointer-events: none")
        .each(function(d) {
          const textElement = d3.select(this);
          const characters = d.name.split(""); // е°Ҷ name жӢҶеҲҶдёәеӯ—з¬Ұж•°з»„
          const num = 6; // жҜҸеҲ—жңҖеӨ§еӯ—з¬Ұж•°
          const columnOffset = 12; // еҲ—зҡ„ж°ҙе№іеҒҸз§»и·қзҰ»
          const set2 = -2; // еӯ—з¬Ұж•°дёә 2 ж—¶пјҢдёҠз§» 10
          const set3 = 1.5; // еӯ—з¬Ұж•°дёә 3 ж—¶пјҢдёҠз§» 15
          const set4 = 5; // еӯ—з¬Ұж•°дёә 3 ж—¶пјҢдёҠз§» 15
          const set5 = 8;  // еӯ—з¬Ұж•°еӨ§дәҺ 5 ж—¶пјҢдёӢз§» 20

          // и®ҫзҪ® x еҒҸз§»йҮҸеҸӮж•°
          const setX2 = 6; // еҲ—ж•°дёә 2 ж—¶пјҢx еҒҸз§»
          const setX3 = 12; // еҲ—ж•°дёә 3 ж—¶пјҢx еҒҸз§»
          const setX4 = 11; // еҲ—ж•°дёә 3 ж—¶пјҢx еҒҸз§»

          // еҠЁжҖҒи°ғж•ҙзҲ¶иҠӮзӮ№зҡ„ y еҒҸз§»
          const totalCharacters = characters.length;
          let yOffset = 0; // й»ҳи®ӨеҒҸз§»йҮҸдёә 0
          if (totalCharacters === 2) {
            yOffset = set2; // еҪ“еӯ—з¬Ұж•°дёә 2 ж—¶пјҢи°ғж•ҙ y еҒҸз§»йҮҸ
          } else if (totalCharacters === 3) {
            yOffset = set3; // еҪ“еӯ—з¬Ұж•°дёә 3 ж—¶пјҢи°ғж•ҙ y еҒҸз§»йҮҸ
          } else if (totalCharacters === 4) {
            yOffset = set4; // еҪ“еӯ—з¬Ұж•°дёә 3 ж—¶пјҢи°ғж•ҙ y еҒҸз§»йҮҸ
          } else if (totalCharacters >= 5) {
            yOffset = set5; // еҪ“еӯ—з¬Ұж•°еӨ§дәҺ 5 ж—¶пјҢи°ғж•ҙ y еҒҸз§»йҮҸ
          }
          textElement.attr("y", +textElement.attr("y") + yOffset); // жӣҙж–°зҲ¶иҠӮзӮ№зҡ„ y еқҗж Ү
          // еҠЁжҖҒи®Ўз®—иЎҢй«ҳ
          const lineHeight = totalCharacters <= num ? 6 / totalCharacters : 1;

          // еҠЁжҖҒи°ғж•ҙзҲ¶иҠӮзӮ№зҡ„ x еҒҸз§»
          const totalColumns = Math.ceil(totalCharacters / num); // и®Ўз®—еҲ—ж•°
          let xOffset = 0; // й»ҳи®Ө x еҒҸз§»дёә 0
          if (totalColumns === 2) {
            xOffset = setX2; // еҲ—ж•°дёә 2 ж—¶пјҢи°ғж•ҙ x еҒҸз§»
          } else if (totalColumns === 3) {
            xOffset = setX3; // еҲ—ж•°дёә 3 ж—¶пјҢи°ғж•ҙ x еҒҸз§»
          }else if (totalColumns === 4) {
            xOffset = setX4; // еҲ—ж•°дёә 3 ж—¶пјҢи°ғж•ҙ x еҒҸз§»
          }
          textElement.attr("x", +textElement.attr("x") + xOffset); // жӣҙж–°зҲ¶иҠӮзӮ№зҡ„ x еқҗж Ү

          characters.forEach((char, index) => {
            const column = Math.floor(index / num); // еҪ“еүҚеӯ—з¬Ұзҡ„еҲ—еҸ·
            const row = index % num; // еҪ“еүҚеӯ—з¬ҰеңЁеҲ—дёӯзҡ„иЎҢеҸ·

            textElement.append("tspan")
              .attr("x", +textElement.attr("x") - column * columnOffset) // еҗ‘е·ҰеҒҸз§»
              .attr("dy", row === 0 && column > 0 ? `-${(num - 1) * lineHeight}em` : lineHeight + "em")
              .text(char); // и®ҫзҪ® tspan зҡ„ж–Үжң¬еҶ…е®№
          });
        });

      console.log("Relating data completed");
    },

    // з»ҳеҲ¶ең°зӮ№еңҶеңҲ
    async drawLocationCircles(svg, projection, locations) {
      return new Promise((resolve) => {
        svg.append("g")
          .selectAll("circle")
          .data(this.locations)
          .enter()
          .append("circle")
          .attr("cx", (d) => projection([d.lon, d.lat])[0]) // з»ҸеәҰе’Ңзә¬еәҰиҪ¬дёәеқҗж Ү
          .attr("cy", (d) => projection([d.lon, d.lat])[1])
          .attr("r", 2) // еңҶеңҲеҚҠеҫ„
          .attr("fill", d => 
            this.init === 0 
              ? this.theme.pointBase
              : (locations.includes(d) ? this.theme.pointActive : this.theme.pointBase)
          )
          .style("cursor", "pointer")
          .on("click", (event, d) => {
            this.activateChapterByName(d?.chapter);
          });

        // еңҶеңҲз»ҳеҲ¶е®ҢжҲҗеҗҺи°ғз”Ё resolve
        resolve();
      });
    },

    // з»ҳеҲ¶ең°зӮ№д№Ӣй—ҙзҡ„иҝһжҺҘзәҝ
    async drawLocationLines(svg, projection, locations, len) {
      return new Promise((resolve) => {
        const lineGroup = svg.append("g");
        for (let i = 0; i < this.locations.length - 1; i++) {
          const start = this.locations[i];
          const end = this.locations[i + 1];
          // еҲӨж–ӯз»ҸеәҰжҲ–зә¬еәҰе·®жҳҜеҗҰи¶…иҝҮйҳҲеҖј len
          if (Math.abs(start.lon - end.lon) < len && Math.abs(start.lat - end.lat) < len) {
            const [sx, sy] = projection([start.lon, start.lat]);
            const [ex, ey] = projection([end.lon, end.lat]);
            lineGroup.append("line")
              .attr("class", "location-line") // дёәжҜҸжқЎзәҝж·»еҠ дёҖдёӘ classпјҢдҫҝдәҺеҗҺз»ӯжё…йҷӨ
              .attr("x1", sx)
              .attr("y1", sy)
              .attr("x2", ex)
              .attr("y2", ey)
              .attr("stroke", () => {
                if (this.init === 0) {
                  return this.theme.routeBase;
                } else {
                  // е…¶д»–жғ…еҶөпјҢж №жҚ®ең°зӮ№зҡ„е…ізі»еҶіе®ҡйўңиүІ
                  return locations.includes(start) && locations.includes(end) ? this.theme.routeActive : this.theme.routeBase;
                }
              }) //ең°еӣҫдёҠи·Ҝзәҝзҡ„йўңиүІпјҲеҰӮжһңиҜҘең°зӮ№еұһдәҺеҪ“еүҚз« иҠӮпјҢжҳҫзӨәдёәзәўиүІпјҢеҗҰеҲҷдёәзҒ°иүІпјү
              .attr("stroke-width", 1.6)
              .style("stroke-linecap", "round")
              .style("opacity", 0.78)
              .style("cursor", "pointer")
              .datum({ start, end })
              .on("click", (event, d) => {
                const chapterName = d?.start?.chapter || d?.end?.chapter;
                this.activateChapterByName(chapterName);
              });
          }
        }

        // иҝһжҺҘзәҝз»ҳеҲ¶е®ҢжҲҗеҗҺи°ғз”Ё resolve
        resolve();
      });
    },
    async initMap() {
      try {
        // // жё…йҷӨжүҖжңүе®№еҷЁеҶ…зҡ„еӣҫеғҸе’ҢзҹўйҮҸеӣҫеҪўпјҲSVGпјү
        // const images = container.querySelectorAll('img');
        // images.forEach(img => img.remove());  // з§»йҷӨжүҖжңүеӣҫеғҸ

        // const svgs = container.querySelectorAll('svg');
        // svgs.forEach(svg => svg.remove());  // з§»йҷӨжүҖжңү SVG е…ғзҙ 
        // иҺ·еҸ– `mapContainer` зҡ„ DOM е…ғзҙ 
        const container = this.$refs.mapContainer;
        console.log("Container height:", container.clientHeight);
        // е®ҡд№үең°еӣҫжҠ•еҪұ
        this.projection = d3.geoMercator()
          .center([107, 20]) // ең°еӣҫдёӯеҝғдҪҚзҪ®
          .scale(container.clientHeight * 0.8) // и®ҫзҪ®зј©ж”ҫйҮҸ
          .translate([container.clientWidth / 1.85, container.clientHeight / 1.62]);

        // еҲӣе»ә SVGпјҢе®Ҫй«ҳдҪҝз”Ё CSS жҺ§еҲ¶
        this.svg = d3
          .select(container)
          .append("svg")
          .attr("preserveAspectRatio", "xMidYMid meet") // дҝқжҢҒе®Ҫй«ҳжҜ”
          .attr("viewBox", `0 0 ${container.clientWidth} ${container.clientHeight}`);

        // з»ҳеҲ¶ең°еӣҫи·Ҝеҫ„гҖҒең°зӮ№еңҶеңҲгҖҒиҝһжҺҘзәҝзӯү
        await this.drawMapPath(this.svg, this.projection);
        await this.drawLocationCircles(this.svg, this.projection, this.locations);
        await this.drawLocationLines(this.svg, this.projection, this.locations, this.len);

        // еҲқе§ӢеҢ–ж—¶й—ҙж Үе°ә
        this.initTimeline(this.svg, container.clientHeight / 1.6); // и°ғж•ҙж—¶й—ҙж Үе°әзҡ„дҪҚзҪ®
      } catch (error) {
        console.error("ең°еӣҫж•°жҚ®еҠ иҪҪеӨұиҙҘ:", error);
      }
    },
    initTimeline(mapSvg, mapHeight) {
      // жЈҖжҹҘ mapSvg жҳҜеҗҰжңүж•Ҳ
      if (!mapSvg || !mapSvg.node()) {
        console.error('SVG is not initialized correctly.');
        return;
      }
      const svg = mapSvg.append("g").attr("class", "timeline-group");

      const timelineWidth = mapSvg.node().getBoundingClientRect().width;
      const timelineHeight = 60;  // й«ҳеәҰи®ҫзҪ®дёәеӣәе®ҡзҡ„ 60px

      // и®ҫзҪ®ж—¶й—ҙж Үе°әзҡ„ y еқҗж ҮпјҢдҪҝе…¶дҪҚдәҺең°еӣҫдёӢж–№
      const timelineYPosition = mapHeight + 10; // и°ғж•ҙж—¶й—ҙж Үе°әзҡ„дҪҚзҪ®пјҢж”ҫзҪ®еңЁең°еӣҫдёӢж–№
      this.timelineY = timelineYPosition; // ж—¶й—ҙиҪҙзҡ„ y еқҗж Ү
      this.timelineX = timelineWidth;
      // еҲӣе»әдёҖдёӘж—¶й—ҙиҪҙзҡ„жҜ”дҫӢе°ә
      const xScale = d3.scaleTime()
        .domain([d3.min(this.timeData, d => new Date(d.time)),
          d3.max(this.timeData, d => new Date(d.time))])
        .range([0, timelineWidth]);

      // з»ҳеҲ¶ж—¶й—ҙзәҝзҡ„и·Ҝеҫ„
      const line = d3.line()
        .x(d => xScale(new Date(d.time)))  // ж №жҚ®ж—¶й—ҙжқҘе®ҡдҪҚдҪҚзҪ®
        .y(timelineHeight / 2)  // еӣәе®ҡеңЁеһӮзӣҙдёӯеҝғ
        .curve(d3.curveMonotoneX);  // е№іж»‘жӣІзәҝ
      svg.append("path")
        .data([this.timeData]) // е°ҶжүҖжңүең°зӮ№ж•°жҚ®дҪңдёәи·Ҝеҫ„
        .attr("d", line)
        .attr("fill", "none")
        .attr("stroke", "#b7ae8f")//ж—¶й—ҙж Үе°әзҡ„йўңиүІ
        .attr("stroke-width", 3)
        .attr("marker-end", "url(#arrow)")  // дёәи·Ҝеҫ„ж·»еҠ з®ӯеӨҙж Үи®°
        .attr("transform", `translate(0, ${timelineYPosition})`); // и®ҫзҪ®ж—¶й—ҙж Үе°әзҡ„дҪҚзҪ®

      console.log(xScale(new Date(this.timeData[50].time))); // жү“еҚ°ж—¶й—ҙеҜ№еә”зҡ„Xеқҗж Ү

      // еҸҜйҖүпјҡж·»еҠ ж—¶й—ҙиҪҙеҲ»еәҰ
      const ticks = xScale.ticks(d3.timeYear.every(1)); // жҜҸе№ҙдёҖж ј
      svg.selectAll(".tick")
        .data(ticks)
        .enter().append("line")
        .attr("class", "tick")
        .attr("x1", d => xScale(d))
        .attr("x2", d => xScale(d))
        .attr("y1", 0)
        .attr("y2", timelineHeight)
        .attr("stroke", "#b7ae8f")// и®ҫзҪ®еҲ»еәҰзҡ„йўңиүІ
        .attr("stroke-width", 1)
        .attr("transform", `translate(0, ${timelineYPosition})`); // и®ҫзҪ®еҲ»еәҰзҡ„дҪҚзҪ®

      // е®ҡд№үз®ӯеӨҙзҡ„marker
      svg.append("defs").append("marker")
        .attr("id", "arrow")  // з»ҷз®ӯеӨҙи®ҫзҪ®ID
        .attr("viewBox", "0 0 10 10")  // и®ҫзҪ®з®ӯеӨҙзҡ„и§ҶеҸЈ
        .attr("refX", 8)  // и®ҫзҪ®з®ӯеӨҙзҡ„дҪҚзҪ®еҒҸз§»йҮҸ
        .attr("refY", 5)  // и®ҫзҪ®з®ӯеӨҙзҡ„YеҒҸз§»йҮҸ
        .attr("markerWidth", 4)  // з®ӯеӨҙе®ҪеәҰ
        .attr("markerHeight", 4)  // з®ӯеӨҙй«ҳеәҰ
        .attr("orient", "auto")  // иҮӘеҠЁж—ӢиҪ¬д»ҘйҖӮеә”и·Ҝеҫ„
        .attr("transform", `translate(0, ${timelineYPosition})`) // и®ҫзҪ®еҲ»еәҰзҡ„дҪҚзҪ®
        .append("path")
        .attr("d", "M 0 0 L 10 5 L 0 10 z")  // з»ҳеҲ¶з®ӯеӨҙи·Ҝеҫ„
        .attr("fill", "#b7ae8f");  // и®ҫзҪ®з®ӯеӨҙйўңиүІ
        
    },    

    
    createTooltip(svg, d, event) {
      const { x, y } = this.mouseXY(svg, event);
      const svgRect = svg.node().getBoundingClientRect();
      const boxW = 132;
      const boxH = 44;
      const pad = 10;
      const safeX = Math.max(pad, Math.min(x, svgRect.width - boxW - pad));
      const safeY = Math.max(pad, Math.min(y, svgRect.height - boxH - pad));

      svg
        .append("rect")
        .attr("id", "tooltip-box")
        .attr("x", safeX)
        .attr("y", safeY)
        .attr("width", boxW)
        .attr("height", boxH)
        .attr("rx", 10)
        .attr("ry", 10)
        .attr("fill", "rgba(31, 36, 36, 0.78)")
        .attr("stroke", "rgba(246, 241, 226, 0.55)")
        .attr("stroke-width", 1)
        .attr("opacity", 1);

      svg
        .append("text")
        .attr("id", "tooltip-text")
        .attr("x", safeX + boxW / 2)
        .attr("y", safeY + 28)
        .attr("text-anchor", "middle")
        .attr("font-size", "14px")
        .attr("font-weight", 800)
        .attr("fill", "rgba(246, 241, 226, 0.96)")
        .text(d ? d.properties.name : "");
    },
    removeTooltip() {
      d3.select("#tooltip-box").remove();
      d3.select("#tooltip-text").remove();
    },
    mouseXY(svg, event) {
      const rect = svg.node().getBoundingClientRect();
      return { x: event.clientX - rect.left, y: event.clientY - rect.top };
    },
  },
};
</script>

