<template>
  <div id="app">
    <nav class="navbar x-theme">
      <div class="logo-text" @click="goToSection(0)">еҫҗйңһе®ўжёёи®°еҸҜи§ҶеҢ–</div>
      <ul>
        <li
          v-for="(page, index) in pages"
          :key="index"
          :class="{ active: currentPage === index }"
          @click="goToSection(index)"
        >
          {{ page }}
        </li>
      </ul>
    </nav>

    <div id="fullpage">
      <div
        v-for="(component, index) in pageComponents"
        :key="index"
        class="section"
        :class="'section' + (index + 1)"
      >
        <component :is="component" :pageConfigs="pageConfigs" @navigate="navigateToPage" />
      </div>
    </div>
  </div>
</template>

<script>
import fullpage from 'fullpage.js';
import 'fullpage.js/dist/fullpage.css';
import PageHome from './components/PageHome.vue';
import PageOne from './components/PageOne.vue';
import PageTwo from './components/PageTwo.vue';
import PageThree from './components/PageThree.vue';
import PageFour from './components/PageFour.vue';
import PageFive from './components/PageFive.vue';

export default {
  name: 'App',
  components: {
    PageHome,
    PageOne,
    PageTwo,
    PageThree,
    PageFour,
    PageFive,
  },
  data() {
    return {
      pageConfigs: [
        { title: 'е№іеҸ°йҰ–йЎө', component: PageHome },
        { title: 'жёёи®°и·ҜзәҝеҸҜи§ҶеҢ–', component: PageOne },
        { title: 'жёёи®°жғ…ж„ҹиҜҚз»ҹи®Ў', component: PageTwo },
        { title: 'зңҒд»ҪжёёеҺҶз”ҳзү№еӣҫ', component: PageThree },
        { title: 'еҫҗйңһе®ўдёҺеұұж°ҙеҗҚиғң', component: PageFour },
        { title: 'еҫҗйңһе®ўдёҺеҗ„иүІжҷҜи§Ӯ', component: PageFive },
      ],
      currentPage: 0,
      fullpageInstance: null,
    };
  },
  computed: {
    pages() {
      return this.pageConfigs.map(item => item.title);
    },
    pageComponents() {
      return this.pageConfigs.map(item => item.component);
    }
  },
  mounted() {
    this.fullpageInstance = new fullpage('#fullpage', {
      navigation: false,
      scrollingSpeed: 700,
      anchors: this.pageConfigs.map((_, index) => `page${index + 1}`),
      showActiveTooltip: false,
      licenseKey: 'дҪ зҡ„еҜҶй’Ҙ', // и®°еҫ—ж·»еҠ 
      afterLoad: (origin, destination) => {
        this.currentPage = destination.index;
      },
    });
  },
  methods: {
    goToSection(index) {
      if (this.fullpageInstance) {
        this.fullpageInstance.moveTo(index + 1);
      }
    },
    navigateToPage(pageIndex) {
      // дҫӣеӯҗз»„д»¶и°ғз”ЁпјҢpageIndex жҳҜзӣ®ж ҮйЎөйқўеңЁ fullpage дёӯзҡ„зҙўеј•пјҲ1-basedпјү
      if (this.fullpageInstance) {
        this.fullpageInstance.moveTo(pageIndex);
      }
    }
  },
};
</script>

