                    //Figure out some variable that will determine the path points to create
                    var side, da, angle_sign;
                    if (target_a - source_a < -Math.PI) {
                        // еҪ“зӣ®ж Үи§’еәҰе’Ңиө·е§Ӣи§’еәҰжҸ’еҖје°ҸдәҺ-piеҚіе°ҸдәҺ-180еәҰ cw
