                        } //for j
                    } //if

                    //Attach last point of the curve section
                    line_data.push({
                        angle: end_angle,
                        radius: rad_curve_line,
                    });

                    //Attach last point to data
                    line_data.push({
                        angle: target_a,
                        radius: target_r,
                    });

                    //Draw the path
