          const block = level1[i].children;
          const bookScore = [];
          let bookScoreId;
          for (let star = 0; star < block.length; ++star) {
            let style = (function () {
                bookScoreId = 0;
                return itemStyle.star5;
              }
            )(block[star].name);
            block[star].label = { color: style.color, downplay: { opacity: 0.5 } };
